var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"하아…… 하아……","JPN":"はあ……はあ……","ENG":"Huff, huff...","TWN":"呼呼……呼呼……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"자극 대응 테스트 종료.","JPN":"刺激対応テスト終了。","ENG":"Stimulus-response test completed.","TWN":"刺激反應實驗結束。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L6_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"루시드는 탈진. 참여대상 전원 전투불능 상태. 사상자는 없습니다.","JPN":"ルシードは脱力状態。参加対象は全員戦闘不能状態。死傷者はいません。","ENG":"Lucid is exhausted. All the participants have been incapacitated. No casualties.","TWN":"露西德虛脫，傭兵全員無法作戰，沒有任何傷亡。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"훌륭하군. 아주 훌륭해.","JPN":"素晴らしい、実に素晴らしい。","ENG":"Good. Very good!","TWN":"非常好，表現得很好。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"그렇게 자극을 받은 상황에서도 침식체들이 급소를 전부 피하게 하다니 통제력이 대단해.","JPN":"あんな刺激を受けた状況でも侵食体が急所をすべて避けるようにするとは、統制力がすごいな。","ENG":"Even in such a stressful situation, she made sure the C.O.s didn't hit them where it hurt.","TWN":"受到那樣的刺激，還能讓那些侵蝕體避開要害。非常出色的控制能力！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"이제 실험이 성공했다고 상부에 보고드리기 전에 마지막 테스트만 남았어.","JPN":"実験は成功したと上層部に報告する前に、最後のテストだけが残っている。","ENG":"Now, before I report to the upper management with the success of this test, there's one more thing to do.","TWN":"在我跟上面報告實驗成功之前，還剩下最後一個實驗。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"실전을 통해 이 능력의 한계를 시험할 차례인 거지.","JPN":"実戦によって、この能力の限界を試す時が来た。","ENG":"Really putting this ability to the test in actual battle.","TWN":"就是透過實戰測試這個能力的極限。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"으음……","JPN":"ううん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"……이번에도 외부 용병들을 부를까요?","JPN":"……今回も外部から傭兵を雇いますか？","ENG":"... Should I call more external mercenaries?","TWN":"……這次也要找傭兵嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"그건 예산 낭비다. 게다가 정부에서도 실종자에 대해 신경을 쓰기 시작했어.","JPN":"予算の無駄遣いだ。それに、政府も行方不明者について気にし始めた。","ENG":"That would be a waste of budget. Besides, the government has taken notice of the missing people.","TWN":"這樣有點浪費，而且政府已經開始注意到失蹤者的事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"철수하기 전에 마지막으로 국경에 있는 난민촌에서 루시드의 실험을 진행한다.","JPN":"撤退する前に、国境にある難民村でルシードの最終実験を行う。","ENG":"Before we withdraw, we'll try one last test with Lucid in the refugee camp near the national border.","TWN":"收手前，就在國界的難民村進行實驗吧！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"제대로 된 테스트는 어려울 것 같습니다. 능력이 발현된 건 불과 몇 달 전입니다.","JPN":"能力が発現したのはわずか数ヶ月前なので、まともなテストはまだ難しそうです。","ENG":"I don't think this ability can be tested to the fullest. It's only been a few months since she discovered it.","TWN":"但這個實驗恐怕會有漏洞，畢竟發現這個能力才幾個月而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"현재의 출력으로 유효한 결과를 만들어내는 건 아직 무립니다.","JPN":"現在の出力で有効な結果を生み出すのはまだ厳しいでしょう。","ENG":"She's unable to create any valid results at the moment.","TWN":"以目前的輸出還無法得到準確的結果。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"상부에서 당장 성과를 원하고 있어!","JPN":"上層部は今すぐ成果を求めている！","ENG":"The upper management wants results now!","TWN":"上面現在就想知道結果！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"아인과 실험체들이 사라진 지금, 부진한 성적을 메울 방법은 이것밖에 없단 말이다.","JPN":"アインと実験体たちが消えた今、不振な成績を埋め合わせる方法はこれしかない。","ENG":"Now that we've lost Eins and the other subjects, this is the only way to redeem ourselves.","TWN":"我們已經搞丟了艾茵和實驗體，這是現在唯一可以將功補過的方法！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"아직 미숙한 능력은 맥스웰에서 개발한 신형 CRF 증폭기를 사용하면 해결된다.","JPN":"まだ未熟な能力は、マックスウェル社が開発した新型CRF増幅器を使えば解決できる。","ENG":"Whatever she's incapable of, we can make up for it with Maxwell's new CRF intensifier.","TWN":"尚未成熟的能力就用麥克斯韋公司開發的，新型CRF增幅器去補就好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"루시드는 지금 이미 육체적으로도, 정신적으로 많이 손상이 간 상태입니다.","JPN":"ルシードはすでに肉体的にも精神的にもかなり損傷しています。","ENG":"Lucid has sustained significant damage to her body as well as her mind.","TWN":"露西德現在無論是在肉體上或是精神上，都受到不小的損害。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"증폭기를 사용하면 목숨이 무사하지 못하겠죠. 루시드에겐 마지막 실험이 되겠군요.","JPN":"増幅器を使えば無事では済まないでしょう。\\nルシードにとって最後の実験になりそうですね。","ENG":"That intensifier could be the straw that broke the camel's back. This might be Lucid's last test.","TWN":"再使用增幅器的話，她的身體可能會無法負荷，這很可能會是她的最後一個實驗。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOSS_NPC_BARCODE_NULL","text":{"KOREA":"흥. 공식이 확립됐으니 적성이 맞는 실험체만 다시 찾으면 돼.","JPN":"ふん、公式は確立できているから、適性に合う実験体さえまた見つければいい。","ENG":"Hmpf. We've established the formula. We can always find suitable test subjects.","TWN":"嗯，反正是套公式的，只需要再找合適的實驗體就好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIRECTOR_NPC_BARCODE_NULL","text":{"KOREA":"알겠습니다. 이렇게 된 이상, 적당히 조절할 필요는 없겠군요.","JPN":"わかりました。こうなった以上、適度に調節する必要はなさそうですね。","ENG":"Yes, sir. This means I don't have to go easy on her, either.","TWN":"好的，既然如此，那就不必再做什麼調整囉！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체다! 격리실에 있던 침식체들이 풀려났다!","JPN":"侵食体だ！　隔離室にいた侵食体が解放された！","ENG":"C.O.s! The C.O.s in the isolation chamber have been released!","TWN":"侵蝕體！隔離室裡的侵蝕體被放出來了！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"처리해! 그리고 실험체는…? 프로토타입은 어디 있나! 그 녀석을 찾아!","JPN":"処理しろ！　あと実験体は……？　プロトタイプはどこだ！　あいつを探せ！","ENG":"Get rid of them! And the test subject? Where's the prototype? Find her!","TWN":"把它們都處理掉！實驗體呢…？原型在哪裡？給我把她找出來！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};